import { subscribeToStatus } from 'library';

function Status({ topic }) {
  const [status, setStatus] = useState();

  useEffect(() => {
    const unsubscribe = subscribeToStatus(topic, (status) => {
      setStatus(status);
    });

    return () => unsubscribe();
  }, [topic]);

  return <div>{status}</div>;
}

